const {
  getIslandsWithDuplicatedNameError,
} = require('../../error/get-discovery-error');
const { NordicIslandsError } = require('../../error/nordic-islands-error');

/**
 * @param {import("../../helpers/file-system/islands-manifest").IslandsManifest | {}} islands
 */
const validateIslandsUniqueName = (islands) => {
  /** @type {Map<string, string>} */
  const filesByIslandNameUsed = new Map();
  /** @type {Map<string, string[]>} */
  const duplicatedIslandNames = new Map();

  Object.values(islands).forEach((island) => {
    if (!filesByIslandNameUsed.has(island.name)) {
      filesByIslandNameUsed.set(island.name, island.path);

      return;
    }

    duplicatedIslandNames.set(
      island.name,
      (
        duplicatedIslandNames[island.name] ||
        new Set([filesByIslandNameUsed.get(island.name)])
      ).add(island.path),
    );
  });

  if (!duplicatedIslandNames.size) {
    return;
  }

  throw new NordicIslandsError(
    getIslandsWithDuplicatedNameError(duplicatedIslandNames),
  );
};

module.exports = {
  validateIslandsUniqueName,
};
